export default function PricingCardsSpotlight01() {
  return (
    <section id="pricing" className="px-6 py-20">
      <div className="mx-auto max-w-6xl">
        <h2 className="text-3xl font-bold text-slate-900 dark:text-white">Flexible Preise</h2>
        <p className="mt-2 text-slate-500 dark:text-slate-400">Monatlich kündbar. Kein Risiko.</p>
        <div className="mt-10 grid gap-6 md:grid-cols-3">
          {PLANS.map((plan) => (
            <article key={plan.name} className={`relative rounded-2xl border p-7 ${plan.featured ? "border-indigo-500 bg-indigo-600 text-white ring-4 ring-indigo-500/20" : "border-slate-200 bg-white text-slate-900 dark:border-slate-800 dark:bg-slate-900 dark:text-white"}`}>
              {plan.featured && (
                <span className="absolute -top-3 left-1/2 -translate-x-1/2 rounded-full bg-amber-400 px-3 py-1 text-xs font-bold text-slate-900">
