                </span>
              )}
              <h3 className="text-lg font-semibold">{plan.name}</h3>
              <p className="mt-3 text-4xl font-black">€{plan.price}<span className="text-sm font-medium opacity-70">/mo</span></p>
              <ul className="mt-5 space-y-2 text-sm">
                {plan.points.map((p) => (
                  <li key={p} className="flex items-center gap-2">
                    <span className={`text-base ${plan.featured ? "text-cyan-200" : "text-indigo-500"}`}>✓</span>
                    {p}
                  </li>
                ))}
              </ul>
              <button className={`mt-7 w-full rounded-xl px-4 py-2.5 text-sm font-semibold transition ${plan.featured ? "bg-white text-indigo-700 hover:bg-slate-100" : "bg-slate-900 text-white hover:bg-slate-700 dark:bg-white dark:text-slate-900 dark:hover:bg-slate-100"}`}>
                Auswählen
              </button>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

