            <article key={plan.name} className={`rounded-2xl border p-8 text-left ${plan.featured ? "border-indigo-500 bg-indigo-50 ring-2 ring-indigo-200" : "border-slate-200 bg-white"}`}>
              <h3 className="text-lg font-bold text-slate-900">{plan.name}</h3>
              <p className="mt-1 text-sm text-slate-500">{plan.description}</p>
              <p className="mt-5 text-5xl font-black text-slate-900">
                €{annual ? plan.annual : plan.monthly}<span className="text-base font-medium text-slate-400">/mo</span>
              </p>
              <button className={`mt-7 w-full rounded-xl py-3 text-sm font-semibold transition ${plan.featured ? "bg-indigo-600 text-white hover:bg-indigo-500" : "bg-slate-900 text-white hover:bg-slate-700"}`}>
                Jetzt starten
              </button>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

const FEATURES = ["Bis zu 10 Nutzer", "20 aktive Projekte", "5 GB Speicher", "Email-Support", "Analytics-Dashboard", "API-Zugang", "SSO & SAML", "Dedizierter Accountmanager"];

const TIERS = [
  { name: "Free", price: "0", description: "Perfekt zum Ausprobieren.", featureCount: 2, color: "border-slate-200" },
  { name: "Pro", price: "39", description: "Für wachsende Teams.", featureCount: 5, color: "border-violet-500 ring-2 ring-violet-100", badge: "Beliebt" },
  { name: "Enterprise", price: "Individuell", description: "Für skalierungsstarke Unternehmen.", featureCount: 8, color: "border-slate-800 bg-slate-900 text-white" },
];

export default function PricingHorizontalCards01() {
  return (
    <section id="pricing" className="px-6 py-24">
      <div className="mx-auto max-w-5xl">
        <h2 className="text-center text-3xl font-extrabold text-slate-900">Transparent. Fair. Skalierbar.</h2>
        <p className="mt-3 text-center text-slate-500">Monatlich kündbar. Kein Vendor-Lock-in.</p>
        <div className="mt-12 grid gap-6 md:grid-cols-3">
          {TIERS.map((tier) => (
            <article key={tier.name} className={`relative rounded-3xl border p-7 ${tier.color}`}>
              {tier.badge && (
                <span className="absolute -top-3 left-1/2 -translate-x-1/2 rounded-full bg-violet-600 px-4 py-1 text-xs font-bold text-white">
                  {tier.badge}
                </span>
              )}
              <h3 className={`text-lg font-bold ${tier.name === "Enterprise" ? "text-white" : "text-slate-900"}`}>{tier.name}</h3>
              <p className={`mt-1 text-xs ${tier.name === "Enterprise" ? "text-slate-400" : "text-slate-500"}`}>{tier.description}</p>
              <p className={`mt-5 text-4xl font-black ${tier.name === "Enterprise" ? "text-white" : "text-slate-900"}`}>
                {tier.price === "Individuell" ? <span className="text-2xl">Auf Anfrage</span> : <>${tier.price}<span className="text-sm font-normal opacity-60">/mo</span></>}
              </p>
              <ul className={`mt-6 space-y-2 text-sm ${tier.name === "Enterprise" ? "text-slate-300" : "text-slate-600"}`}>
                {FEATURES.slice(0, tier.featureCount).map((f) => (
                  <li key={f} className="flex items-center gap-2">
                    <span className="text-emerald-500">✓</span>{f}
                  </li>
                ))}
              </ul>
              <button className={`mt-8 w-full rounded-2xl py-2.5 text-sm font-bold transition ${tier.name === "Enterprise" ? "bg-white text-slate-900 hover:bg-slate-100" : tier.name === "Pro" ? "bg-violet-600 text-white hover:bg-violet-500" : "border border-slate-200 text-slate-700 hover:bg-slate-50"}`}>
                {tier.name === "Enterprise" ? "Kontakt aufnehmen" : "Jetzt starten"}
              </button>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

